import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"RFC 0004 — Per-plugin database","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0004-per-plugin-database.md","filePath":"rfcs/0004-per-plugin-database.md"}'),s={name:"rfcs/0004-per-plugin-database.md"};function n(r,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-0004-—-per-plugin-database" tabindex="-1">RFC 0004 — Per-plugin database <a class="header-anchor" href="#rfc-0004-—-per-plugin-database" aria-label="Permalink to &quot;RFC 0004 — Per-plugin database&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Manifest schema (<code>packages/manifest</code>), DB layer (<code>packages/db</code>), migration runner, runtime SDK bridge (<code>sdk.db</code>), SRS<br><strong>Incorporated into plan:</strong> Yes — implemented in Task 0.8.1 (<code>@sovereignfs/db</code> 1.5.0, <code>@sovereignfs/sdk</code> 1.9.0, <code>runtime</code> 0.26.0).</p><p>See <a href="./../plugin-database.html"><code>docs/plugin-database.md</code></a> for the operator/author reference.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Let a plugin opt into a <strong>dedicated database</strong> instead of sharing the platform database, via the manifest field that <strong>already exists</strong> but is unimplemented:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;database&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;shared&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;isolated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// default: &quot;shared&quot;</span></span></code></pre></div><p><code>shared</code> (today&#39;s behaviour) keeps the plugin&#39;s tables in the one platform database, namespaced by slug prefix. <code>isolated</code> gives the plugin its <strong>own store</strong> — a separate SQLite file, or a separate Postgres schema/database — which the runtime hands the plugin through <code>sdk.db.getClient()</code>. This buys schema freedom, a clean data lifecycle (uninstall drops the whole store), per-plugin backup/export, and stronger blast-radius isolation, at the cost of extra connections/migration runners and no cross-plugin SQL.</p><p><strong>Shared stays the default.</strong> Isolation is opt-in for plugins that genuinely need it.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The platform deliberately chose <strong>one shared database with slug-prefixed tables</strong> for simplicity (SRS §3.7, decision log): one connection, one migration runner, no cross-plugin query complexity. That is the right default and stays so.</p><p>But some plugins want more than a namespace:</p><ul><li><strong>Clean data lifecycle / right-to-be-forgotten.</strong> Uninstalling a plugin (or purging its data) should be a single, total operation — drop a file or a schema — not a careful sweep of prefixed tables that risks orphans.</li><li><strong>Per-plugin backup, export, and portability.</strong> A self-contained store can be snapshotted, moved, or handed to the user without entangling other plugins&#39; data.</li><li><strong>Blast-radius isolation.</strong> A plugin&#39;s heavy/abusive workload, a runaway migration, or corruption is contained to its own store.</li><li><strong>Schema freedom.</strong> Inside its own store a plugin needn&#39;t carry the slug prefix and can&#39;t accidentally collide with another plugin&#39;s table names.</li></ul><p><code>database: &quot;isolated&quot;</code> was reserved in the manifest from the start precisely to leave room for this; the field exists today but is documented as &quot;not implemented in v1&quot; (SRS §4.6/§5). This RFC designs it as a <strong>post-v1</strong> capability.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>The manifest field already exists:</strong> <code>database?: &#39;shared&#39; | &#39;isolated&#39;</code> (<code>packages/manifest/src/schema.ts</code>, SRS §5). <code>isolated</code> is declared but unimplemented (SRS §4.6).</li><li><strong>The DB factory already has the seam:</strong> <code>createClient({ dialect?, url? })</code> (<code>packages/db/src/client.ts</code>) accepts per-call dialect/URL overrides; <code>resolveSqlitePath</code> resolves relative <code>file:</code> paths against the workspace root into <code>data/</code>. (Postgres is recognised but not wired until Task 0.5.3.)</li><li><strong><code>sdk.db.getClient()</code></strong> (Task 0.5.5) is the single point where the runtime decides which client a plugin receives — the natural place to route an isolated plugin to its dedicated store.</li><li><strong>Per-plugin migrations are already the model:</strong> SRS §3.7 plans migration files under <code>plugins/[id]/migrations/</code>, aggregated by the <code>packages/db</code> runner.</li><li><strong>Existing invariants to honour:</strong> dialect-agnostic (SQLite default, Postgres via env), <code>tenant_id</code> on user-scoped tables, and the SDK boundary (plugins never read another plugin&#39;s data directly).</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="_1-shared-default-vs-isolated-opt-in" tabindex="-1">1. <code>shared</code> (default) vs <code>isolated</code> (opt-in) <a class="header-anchor" href="#_1-shared-default-vs-isolated-opt-in" aria-label="Permalink to &quot;1. `shared` (default) vs `isolated` (opt-in)&quot;">​</a></h3><p><code>database</code> is resolved at plugin-load time from the manifest. <code>shared</code> (or the field omitted) is unchanged: prefixed tables in the platform DB. <code>isolated</code> provisions a dedicated store on first use. <strong>Platform/chrome plugins (Console/Account/Launcher) are always <code>shared</code></strong> — they are core and co-located with platform tables.</p><h3 id="_2-isolation-mechanism-by-dialect" tabindex="-1">2. Isolation mechanism by dialect <a class="header-anchor" href="#_2-isolation-mechanism-by-dialect" aria-label="Permalink to &quot;2. Isolation mechanism by dialect&quot;">​</a></h3><ul><li><strong>SQLite</strong> → a dedicated file per plugin, e.g. <code>data/plugins/&lt;pluginId&gt;.db</code>, created via <code>createClient({ url: &#39;file:./data/plugins/&lt;id&gt;.db&#39; })</code>. The existing <code>resolveSqlitePath</code> + <code>mkdirSync</code> already handle the path and directory.</li><li><strong>Postgres</strong> → two candidate mechanisms (see Open questions; <strong>schema-per-plugin recommended</strong>): <ul><li><strong>Schema-per-plugin (recommended):</strong> one connection/pool; each isolated plugin gets its own Postgres schema (<code>CREATE SCHEMA</code>, <code>search_path</code>/qualified names). Light, keeps a single pool, fits the &quot;one connection&quot; ethos, easy to drop (<code>DROP SCHEMA … CASCADE</code>).</li><li><strong>Database-per-plugin (alternative):</strong> a separate Postgres database + connection per plugin. Strongest isolation and the cleanest backup/drop, but a <strong>connection pool per plugin</strong> (exhaustion risk at scale) and heavier ops (provisioning a database needs elevated privileges).</li></ul></li></ul><h3 id="_3-client-routing" tabindex="-1">3. Client routing <a class="header-anchor" href="#_3-client-routing" aria-label="Permalink to &quot;3. Client routing&quot;">​</a></h3><p>The runtime&#39;s <code>sdk.db</code> bridge consults the plugin&#39;s resolved <code>database</code> setting and returns either the shared platform client or a <strong>dedicated client</strong> built from <code>createClient({ dialect, url })</code>. A small <strong>per-plugin client registry</strong> (keyed by plugin id) caches clients and initialises them <strong>lazily</strong> on first <code>getClient()</code>. Plugins call <code>sdk.db.getClient()</code> exactly as before — isolation is transparent to plugin code.</p><h3 id="_4-migrations" tabindex="-1">4. Migrations <a class="header-anchor" href="#_4-migrations" aria-label="Permalink to &quot;4. Migrations&quot;">​</a></h3><p>Each isolated plugin runs <strong>its own migrations against its own store</strong>, with its <strong>own migration-tracking table</strong> (so version state is per-database). The <code>packages/db</code> runner routes per plugin: platform migrations against the platform DB first, then each plugin&#39;s migrations against its resolved store (shared → the platform DB; isolated → its dedicated store). This extends the §3.7 aggregation model rather than replacing it.</p><h3 id="_5-slug-prefix-inside-an-isolated-store" tabindex="-1">5. Slug prefix inside an isolated store <a class="header-anchor" href="#_5-slug-prefix-inside-an-isolated-store" aria-label="Permalink to &quot;5. Slug prefix inside an isolated store&quot;">​</a></h3><p>Inside its own database a plugin <strong>no longer needs the slug prefix</strong> — schema freedom is a stated benefit. The trade-off: dropping the prefix makes a later <strong><code>shared</code> ↔ <code>isolated</code> switch</strong> a table-rename data migration. Options (Open questions): keep the prefix everywhere for switchability, or drop it in isolated stores for cleanliness and treat the mode as fixed at install. Recommendation: treat <code>database</code> as <strong>fixed at install</strong>; switching is an explicit, migration-backed operation, not a manifest toggle.</p><h3 id="_6-lifecycle" tabindex="-1">6. Lifecycle <a class="header-anchor" href="#_6-lifecycle" aria-label="Permalink to &quot;6. Lifecycle&quot;">​</a></h3><ul><li><strong>Provision</strong> on first <code>getClient()</code> (create the file / <code>CREATE SCHEMA</code>).</li><li><strong>Uninstall / purge</strong> drops the whole store (delete the file / <code>DROP SCHEMA … CASCADE</code>) — a single, total deletion.</li><li><strong>Backup/export</strong> can target one plugin&#39;s store directly.</li></ul><h3 id="_7-boundaries-and-multi-tenancy" tabindex="-1">7. Boundaries and multi-tenancy <a class="header-anchor" href="#_7-boundaries-and-multi-tenancy" aria-label="Permalink to &quot;7. Boundaries and multi-tenancy&quot;">​</a></h3><ul><li><code>tenant_id</code> still applies to user-scoped tables <strong>inside</strong> an isolated store (multi-tenancy readiness is unchanged).</li><li>Isolated stores make cross-plugin <strong>joins impossible</strong>, which <strong>reinforces the SDK boundary</strong> — any cross-plugin read must go through the consent-gated <code>sdk.data</code> mechanism (RFC 0002), never a direct query.</li></ul><h2 id="impact-when-accepted-deferred-—-no-edits-yet" tabindex="-1">Impact when accepted (deferred — no edits yet) <a class="header-anchor" href="#impact-when-accepted-deferred-—-no-edits-yet" aria-label="Permalink to &quot;Impact when accepted (deferred — no edits yet)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where</th><th>Change</th></tr></thead><tbody><tr><td><code>packages/manifest</code></td><td>No schema change (<code>database</code> already exists); document <code>isolated</code> as supported; validation/tests as needed.</td></tr><tr><td><code>packages/db</code></td><td>Per-plugin client factory + registry; Postgres schema (or database) provisioning + drop; reuse <code>createClient</code>.</td></tr><tr><td>Migration runner (<code>packages/db/migrate</code>)</td><td>Route each plugin&#39;s migrations to its resolved store; per-store tracking table.</td></tr><tr><td>Runtime SDK bridge</td><td><code>sdk.db.getClient()</code> returns the shared or dedicated client per the plugin&#39;s <code>database</code> setting.</td></tr><tr><td>Plugin lifecycle (Console / install)</td><td>Provision on first use; drop store on uninstall/purge; per-plugin backup/export hooks.</td></tr><tr><td>SRS §3.7 / §4.6 / §5 / decision log</td><td>Update &quot;no per-plugin DBs&quot; / &quot;not implemented&quot; wording; record the opt-in isolated model and its default-shared.</td></tr><tr><td><code>ROADMAP.md</code></td><td>A phased implementation task (SQLite file isolation first; Postgres schema; lifecycle/backup).</td></tr></tbody></table><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Status quo — shared-only with slug prefixes.</strong> Simplest and stays the <strong>default</strong>, but offers no clean per-plugin deletion, backup, or strong isolation. Rejected as the <em>only</em> option; retained as the default.</li><li><strong>Database-per-plugin for Postgres</strong> (instead of schema-per-plugin). Stronger isolation and cleanest drop/backup, but a connection pool per plugin and heavier provisioning. The primary Open question.</li><li><strong>Bring-your-own / external database now</strong> (operator points a plugin at an external connection string, possibly a different engine). Most flexible but adds secret management, config surface, and dialect-divergence risk. Deferred to a future extension (Open questions).</li><li><strong>A different engine per plugin</strong> (e.g. a document store for one plugin). Out of scope — the platform stays dialect-agnostic over SQLite/Postgres.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Postgres mechanism — schema-per-plugin vs database-per-plugin.</strong> The primary fork; recommendation is schema-per-plugin for the single-pool/light footprint.</li><li><strong>Slug prefix inside isolated stores</strong>, and the <strong><code>shared</code> ↔ <code>isolated</code> switching</strong> story (fixed-at-install vs migration-backed toggle).</li><li><strong>Connection pooling/limits</strong> for Postgres; <strong>lazy vs eager</strong> client init; handling many isolated plugins on one instance.</li><li><strong>Bring-your-own external database</strong> — operator env-config (never manifest secrets); whether a non-platform engine is ever allowed.</li><li><strong>Per-plugin backup/export tooling</strong>, and the <strong>uninstall data policy</strong> (drop immediately vs retain/export-then-drop).</li><li><strong>Provisioning privileges</strong> for Postgres (creating schemas/databases needs rights the runtime DB role may not have by default).</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Accept RFC → confirm <code>database: &quot;isolated&quot;</code> is supported (manifest already carries the field; no schema change) and update the SRS wording.</li><li>Implement <strong>SQLite file isolation</strong> end to end (dedicated file via <code>createClient</code>, per-plugin client registry, per-store migrations) — proves the model with zero new infrastructure.</li><li>Add the <strong>Postgres</strong> mechanism (schema-per-plugin per the resolved Open question) once Postgres is wired (Task 0.5.3).</li><li>Add lifecycle hooks (provision/drop) and per-plugin backup/export; revisit BYO external databases only if there is demand.</li></ol><h2 id="implementation-task-0-8-1" tabindex="-1">Implementation (Task 0.8.1) <a class="header-anchor" href="#implementation-task-0-8-1" aria-label="Permalink to &quot;Implementation (Task 0.8.1)&quot;">​</a></h2><h3 id="open-questions-resolved" tabindex="-1">Open questions resolved <a class="header-anchor" href="#open-questions-resolved" aria-label="Permalink to &quot;Open questions resolved&quot;">​</a></h3><ol><li><p><strong>Postgres mechanism:</strong> schema-per-plugin (<code>CREATE SCHEMA IF NOT EXISTS &quot;plugin_&lt;slug&gt;&quot;</code>). A separate <code>pg.Pool</code> per isolated plugin with <code>SET search_path TO &quot;plugin_&lt;slug&gt;&quot;</code> on every new connection. Separate pool objects (not connections) — the &quot;no extra pool&quot; intent was about not spawning a separate Postgres database; small pool objects are acceptable overhead.</p></li><li><p><strong>Slug prefix in isolated stores:</strong> not required. <code>database</code> is treated as fixed at install — switching is a migration-backed explicit operation, not a manifest toggle. Slug prefix is documented as optional for isolated stores and recommended to drop.</p></li><li><p><strong>Connection pooling:</strong> lazy per-plugin <code>pg.Pool</code>; created on first <code>getPluginDb()</code> call and cached in-process. Plugin pool shares the same server as the platform pool. No connection-count concern unless an operator installs dozens of isolated plugins.</p></li><li><p><strong>BYO external database:</strong> deferred. The <code>DATABASE_URL</code>/<code>DB_DIALECT</code> env-config approach mentioned in Open question 4 is still the path if needed; not built in this task.</p></li><li><p><strong>Per-plugin backup/export:</strong> covered by <code>sv backup</code> (all SQLite files under <code>data/</code> are included; Postgres schemas are in the same database captured by <code>pg_dump</code>). A single-plugin SQLite file can be copied directly. Fine-grained <code>sv backup --plugin &lt;id&gt;</code> is deferred.</p></li><li><p><strong>Provisioning privileges:</strong> for Postgres, <code>CREATE SCHEMA</code> requires the runtime DB role to have <code>CREATE</code> privilege on the database (standard default for the database owner). No additional setup documented; self-hosters who use a restricted role need to grant <code>CREATE ON DATABASE</code> manually.</p></li></ol><h3 id="what-shipped" tabindex="-1">What shipped <a class="header-anchor" href="#what-shipped" aria-label="Permalink to &quot;What shipped&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Change</th></tr></thead><tbody><tr><td><code>packages/db/src/plugin-client.ts</code> (new)</td><td><code>getPluginDb</code>, <code>provisionPluginDb</code>, <code>dropPluginDb</code>, <code>pluginMigrationsFolder</code>, <code>pluginSchemaName</code>, <code>pluginSqliteUrl</code></td></tr><tr><td><code>packages/db/src/migrate.ts</code></td><td><code>runPluginMigrations(pluginDb, folder)</code></td></tr><tr><td><code>packages/db/src/index.ts</code></td><td>All new exports</td></tr><tr><td><code>packages/sdk/src/db.ts</code></td><td>Reads <code>x-sovereign-plugin-id</code> header; passes <code>pluginId</code> to host</td></tr><tr><td><code>packages/sdk/src/host.ts</code></td><td><code>SdkHost.db.getClient(pluginId: string | null)</code></td></tr><tr><td><code>runtime/src/sdk-host.ts</code></td><td>Routes <code>isolated</code> plugins to dedicated client</td></tr><tr><td><code>runtime/src/plugin-migrations.ts</code> (new)</td><td>Startup migration runner for isolated plugins</td></tr><tr><td><code>runtime/instrumentation.ts</code></td><td>Calls plugin migration runner at boot</td></tr><tr><td><code>bin/sv.ts</code></td><td><code>plugin remove</code> reads manifest before delete; drops store; <code>--keep-data</code> flag</td></tr><tr><td><code>docs/plugin-database.md</code> (new)</td><td>Full operator/author reference</td></tr><tr><td>SRS §3.7, §4.6, §5</td><td>Updated &quot;not implemented&quot; → implemented</td></tr></tbody></table><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Added to the roadmap as exploratory Task 0.8.1 (gated on acceptance; still Draft).</td></tr><tr><td>0.3</td><td>Jun 2026</td><td>RFC accepted; status updated to Accepted; Task 0.8.1 now scheduled (no implementation yet).</td></tr><tr><td>0.4</td><td>Jun 2026</td><td>Implemented in Task 0.8.1; status updated to Implemented; open questions resolved.</td></tr></tbody></table>',46)])])}const u=t(s,[["render",n]]);export{h as __pageData,u as default};
